sql:
SELECT AVG(min_bid) AS average_minimum_bid
FROM records
WHERE record_id IN (SELECT record_id FROM bids);

SELECT SUM(s.sale_price * s.quantity) AS total_sales_revenue
FROM sales s
WHERE s.store_id = 1 AND s.sale_date LIKE '2023-05-%';
